#include <iostream>

using namespace std;

int main()
{
    int age = 25;
    int &ageRef = age;

    ageRef = 30; // changes age itself

    cout << age << endl;
    cout << ageRef << endl;

    return 0;
}

int a = 5;
int b = 10;

int &ref = a;
ref = b; // this does NOT make ref refer to b — it copies b's VALUE into a!

cout << a; // 10

